_COLORMAP_GRAYSCALE = np.stack([
    np.arange(256, dtype=np.uint8),
    np.arange(256, dtype=np.uint8),
    np.arange(256, dtype=np.uint8),
], axis=-1)

_COLORMAPS = {
    "viridis": _COLORMAP_VIRIDIS,
    "plasma": _COLORMAP_PLASMA,
    "jet": _COLORMAP_JET,
    "hot": _COLORMAP_HOT,
    "cool": _COLORMAP_COOL,
    "turbo": _COLORMAP_TURBO,
    "grayscale": _COLORMAP_GRAYSCALE,
}


def apply_colormap(depth, cmap_name="viridis"):
    """Apply a colormap to a normalized [0,1] depth array. Returns uint8 RGB."""
    lut = _COLORMAPS.get(cmap_name, _COLORMAP_VIRIDIS)
    depth = np.clip(depth, 0.0, 1.0)
    indices = (depth * 255).astype(np.uint8)
    return lut[indices]
